// Timer-triggered function — fires automatically on schedule in Azure
// but can be triggered manually via the Functions panel in VS during debug
[Function("DailyCleanup")]
public async Task Run(
    [TimerTrigger("0 0 2 * * *")] TimerInfo timerInfo,
    FunctionContext context)
{
    var logger = context.GetLogger<DailyCleanup>();
    // Set breakpoint here — hit it by right-clicking the function
    // in VS Output > Azure Functions > "Execute Function Now"
    logger.LogInformation("Timer triggered at: {time}", DateTime.UtcNow);
    await CleanupOldRecordsAsync();
}
